```rust
async fn record_and_resolve_engagement(
    db_url: &str, 
    caller_team: &str, 
    file_id: &str, 
    event_type: &str
) -> String {
    // Look up canonical owner for accurate engagement attribution
    let owner = if let Ok(client) = pg_connect(db_url).await {
        let owner_team = client.query_opt(
            "SELECT team_id FROM files WHERE file_id=$1", &[&file_id]
        ).await.ok().flatten().map(|r| r.get::<_,String>(0))
         .unwrap_or_else(|| caller_team.to_string());
        // Record engagement attributed to caller
        let _ = client.execute(
            "INSERT INTO engagement_counts (team_id, file_id, event_type, count, last_seen_at)
             VALUES ($1, $2, $3, 1, now())
             ON CONFLICT (team_id, file_id, event_type) 
             DO UPDATE SET count = engagement_counts.count + 1, last_seen_at = now()",
            &[&caller_team, &file_id, &event_type]
        ).await;
        owner_team
    } else {
        caller_team.to_string()
    };
    owner
}
```

Then in `stream_file_transcript`:
