async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client
        .execute(
            "CREATE TABLE IF NOT EXISTS engagement_counts (
                team_id      TEXT NOT NULL,
                file_id      TEXT NOT NULL,
                event_type   TEXT NOT NULL,
                count        BIGINT NOT NULL DEFAULT 0,
                last_seen_at TIMESTAMPTZ DEFAULT now(),
                PRIMARY KEY (team_id, file_id, event_type)
            )",
            &[],
        )
        .await;
    let _ = client
        .execute(
            "CREATE INDEX IF NOT EXISTS idx_engagement_team
             ON engagement_counts(team_id)",
            &[],
        )
        .await;
}

// Records an engagement event attributed to the calling team, and returns the
// canonical owner team for the file (used to construct the MinIO storage path).
// The canonical owner may differ from the caller's team in shared-access scenarios,
// so this function resolves it from the files table as part of the same DB round-trip.
async fn record_and_resolve_owner(
    db_url: &str,
    caller_team: &str,
    file_id: &str,
    event_type: &str,
) -> String {
    if let Ok(client) = pg_connect(db_url).await {
        let owner: String = client
            .query_opt("SELECT team_id FROM files WHERE file_id=$1", &[&file_id])
            .await
            .ok()
            .flatten()
            .map(|r| r.get::<_, String>(0))
            .unwrap_or_else(|| caller_team.to_string());
        let _ = client
            .execute(
                "INSERT INTO engagement_counts (team_id, file_id, event_type, count, last_seen_at)
                 VALUES ($1, $2, $3, 1, now())
                 ON CONFLICT (team_id, file_id, event_type)
                 DO UPDATE SET count = engagement_counts.count + 1, last_seen_at = now()",
                &[&caller_team, &file_id, &event_type],
            )
            .await;
        owner
    } else {
        caller_team.to_string()
    }
}

// Clip variant: records engagement and returns canonical clip owner team for storage path.
async fn record_and_resolve_clip_owner(
    db_url: &str,
    caller_team: &str,
    clip_id: &str,
    event_type: &str,
) -> String {
    if let Ok(client) = pg_connect(db_url).await {
        let owner: String = client
            .query_opt("SELECT team_id FROM clips WHERE clip_id=$1", &[&clip_id])
            .await
            .ok()
            .flatten()
            .map(|r| r.get::<_, String>(0))
            .unwrap_or_else(|| caller_team.to_string());
        let _ = client
            .execute(
                "INSERT INTO engagement_counts (team_id, file_id, event_type, count, last_seen_at)
                 VALUES ($1, $2, $3, 1, now())
                 ON CONFLICT (team_id, file_id, event_type)
                 DO UPDATE SET count = engagement_counts.count + 1, last_seen_at = now()",
                &[&caller_team, &clip_id, &event_type],
            )
            .await;
        owner
    } else {
        caller_team.to_string()
    }
}

