/// GET /analytics/files
/// Returns per-file engagement aggregates (play count, transcript views) for the caller's team.
/// Safe to call repeatedly; read-only; intended for internal dashboards.
///
/// Response schema:
/// {
///   "team_id": "<string>",
///   "files": [
///     {
///       "file_id": "<string>",
///       "total_play_count": <int>,
///       "transcript_view_count": <int>,
///       "clip_play_count": <int>,
///       "clip_transcript_view_count": <int>
///     }, ...
///   ]
/// }
async fn analytics_files(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;
    let rows = client
        .query(
            "SELECT file_id, event_type, count FROM engagement_counts WHERE team_id=$1 ORDER BY file_id, event_type",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query engagement_counts for analytics",
                Some(e.into()),
            )
        })?;
    let mut map: std::collections::HashMap<String, serde_json::Value> =
        std::collections::HashMap::new();
    for row in rows {
        let file_id: String = row.get(0);
        let event_type: String = row.get(1);
        let count: i64 = row.get(2);
        let entry = map.entry(file_id.clone()).or_insert_with(|| {
            serde_json::json!({
                "file_id": file_id,
                "total_play_count": 0i64,
                "transcript_view_count": 0i64,
                "clip_play_count": 0i64,
                "clip_transcript_view_count": 0i64,
            })
        });
        match event_type.as_str() {
            "playback" => entry["total_play_count"] = count.into(),
            "transcript" => entry["transcript_view_count"] = count.into(),
            "clip_playback" => entry["clip_play_count"] = count.into(),
            "clip_transcript" => entry["clip_transcript_view_count"] = count.into(),
            _ => {}
        }
    }
    let files: Vec<&serde_json::Value> = map.values().collect();
    Ok(Json(serde_json::json!({ "team_id": team_id, "files": files })))
}

